<?php
 namespace WPAICG\Images\Providers; use WPAICG\Images\AIPKit_Image_Base_Provider_Strategy; use WP_Error; if (!defined('ABSPATH')) { exit; } class AIPKit_Image_Pixabay_Provider_Strategy extends AIPKit_Image_Base_Provider_Strategy { public function generate_image(string $prompt, array $api_params, array $options = []): array|WP_Error { $api_key = $api_params['api_key'] ?? null; if (empty($api_key)) { return new WP_Error('pixabay_missing_key', __('Pixabay API Key is required.', 'gpt3-ai-content-generator')); } $num_images_to_fetch = isset($options['n']) ? absint($options['n']) : 1; $per_page_for_api = max(3, min($num_images_to_fetch, 200)); $query_args = [ 'key' => $api_key, 'q' => urlencode($prompt), 'per_page' => $per_page_for_api, 'safesearch' => 'true', ]; if (isset($options['page']) && $options['page'] > 0) { $query_args['page'] = absint($options['page']); } if (!empty($options['orientation']) && $options['orientation'] !== 'all') { $query_args['orientation'] = $options['orientation']; } if (!empty($options['image_type']) && $options['image_type'] !== 'all') { $query_args['image_type'] = $options['image_type']; } if (!empty($options['category'])) { $query_args['category'] = $options['category']; } $base_url = 'https://pixabay.com/api/'; $url = add_query_arg($query_args, $base_url); $headers = $this->get_api_headers($api_key, 'generate'); $request_options = $this->get_request_options('generate'); $request_args = array_merge($request_options, ['headers' => $headers]); $response = wp_remote_get($url, $request_args); if (is_wp_error($response)) { return new WP_Error('pixabay_http_error', __('HTTP error during Pixabay API request.', 'gpt3-ai-content-generator')); } $status_code = wp_remote_retrieve_response_code($response); $body = wp_remote_retrieve_body($response); if ($status_code !== 200) { $error_msg = $this->parse_error_response($body, $status_code, 'Pixabay'); return new WP_Error('pixabay_api_error', sprintf(__('Pixabay API Error (%1$d): %2$s', 'gpt3-ai-content-generator'), $status_code, $error_msg)); } $decoded_response = $this->decode_json($body, 'Pixabay Image Search'); if (is_wp_error($decoded_response)) { return $decoded_response; } $images = []; if (isset($decoded_response['hits']) && is_array($decoded_response['hits'])) { $hits_to_process = array_slice($decoded_response['hits'], 0, $num_images_to_fetch); foreach ($hits_to_process as $hit) { $images[] = [ 'url' => $hit['largeImageURL'] ?? ($hit['webformatURL'] ?? ''), 'b64_json' => null, 'revised_prompt' => null, 'photographer' => $hit['user'] ?? null, 'alt' => $hit['tags'] ?? null, ]; } } return ['images' => $images, 'usage' => null]; } public function get_supported_sizes(): array { return []; } public function get_request_options(string $operation): array { $options = parent::get_request_options($operation); $options['method'] = 'GET'; return $options; } public function get_api_headers(string $api_key, string $operation): array { $headers = parent::get_api_headers($api_key, $operation); unset($headers['Content-Type']); return $headers; } } 